import axios from "axios";

// Backend API URL
const BACKEND_URL = "http://localhost:5000";

export const sendMessageToAI = async (message) => {
  try {
    console.log("Sending message to backend:", message);

    const response = await axios.post(
      `${BACKEND_URL}/api/chat`,
      {
        message: message
      },
      {
        headers: {
          "Content-Type": "application/json",
        },
      }
    );

    console.log("Backend response:", response.data);
    return response.data.choices[0].message.content;

  } catch (error) {
    console.error("Backend API ERROR:", error.response?.data || error.message);

    // Handle different types of errors
    if (error.response) {
      // Backend responded with error
      const errorMessage = error.response.data?.error || "Backend error";
      console.error("Backend error details:", error.response.data);
      throw new Error(errorMessage);
    } else if (error.request) {
      // Network error
      console.error("Network error:", error.message);
      throw new Error("Failed to connect to backend server");
    } else {
      // Other error
      console.error("Unknown error:", error.message);
      throw new Error("An unexpected error occurred");
    }
  }
};

/**
 * Generate image using backend API
 * @param {string} prompt - Image generation prompt
 * @param {string} style - Image style preference
 * @param {string} size - Image size preference
 * @returns {Promise<string>} - Generated image URL
 */
export const generateImage = async (prompt, style = 'realistic', size = 'medium') => {
  try {
    console.log("Sending image generation request to backend:", { prompt, style, size });

    const response = await axios.post(
      `${BACKEND_URL}/api/image`,
      {
        prompt: prompt,
        style: style,
        size: size
      },
      {
        headers: {
          "Content-Type": "application/json",
        },
      }
    );

    console.log("Backend image response:", response.data);

    // Extract image URL from response
    const imageUrl = response.data.imageUrl;

    if (!imageUrl) {
      throw new Error('No image URL received from backend');
    }

    return imageUrl;

  } catch (error) {
    console.error("Backend Image Generation Error:", error.response?.data || error.message);

    // Handle different types of errors
    if (error.response) {
      // Backend responded with error
      const errorMessage = error.response.data?.error || "Backend image error";
      console.error("Backend image error details:", error.response.data);
      throw new Error(errorMessage);
    } else if (error.request) {
      // Network error
      console.error("Network error:", error.message);
      throw new Error("Failed to connect to backend server for image generation");
    } else {
      // Other error
      console.error("Unknown error:", error.message);
      throw new Error("An unexpected error occurred during image generation");
    }
  }
};
